        try {
            while (!queue.isEmpty()) {
                Source s = queue.poll();
                SearchRow row = s.next();

                if (uniqueColumnColumn > 0 && !mayHaveNullDuplicates(row)) {
                    checkUnique(false, dataMap, row, Long.MIN_VALUE);
